def range_summary(nums):
    if not nums:
        return ''

    unique_nums = sorted(set(nums))
    ranges = []

    start_num = unique_nums[0]
    end_num = unique_nums[0]

    for num in unique_nums[1:]:
        if num == end_num + 1:
            end_num = num
        else:
            if start_num == end_num:
                ranges.append(str(start_num))
            else:
                ranges.append(f'{start_num}-{end_num}')
            start_num = num
            end_num = num

    if start_num == end_num:
        ranges.append(str(start_num))
    else:
        ranges.append(f'{start_num}-{end_num}')

    return ','.join(ranges)
